package com.blissless.tensei.ui.screens.playerimport androidx.compose.foundation.backgroundimport androidx.compose.foundation.layout.Arrangementimport androidx.compose.foundation.layout.Columnimport androidx.compose.foundation.layout.sizeimport androidx.compose.ui.unit.dpimport androidx.compose.material3.Iconimport androidx.compose.material3.IconButtonimport androidx.compose.material3.MaterialThemeimport androidx.compose.material3.Textimport androidx.compose.runtime.Composableimport androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.graphics.Colorimport androidx.compose.ui.graphics.vector.ImageVector@Composablefun SkipIconButton(    icon: ImageVector,    label: String,    backgroundColor: Color,    iconTint: Color,    onClick: () -> Unit) {    Column(        horizontalAlignment = Alignment.CenterHorizontally,        verticalArrangement = Arrangement.spacedBy(4.dp)    ) {        IconButton(            onClick = onClick,            modifier = Modifier.size(48.dp).background(backgroundColor, shape = MaterialTheme.shapes.small)        ) {            Icon(imageVector = icon, contentDescription = null, tint = iconTint, modifier = Modifier.size(28.dp))        }        Text(text = label, style = MaterialTheme.typography.labelSmall, color = Color.White, maxLines = 2, textAlign = androidx.compose.ui.text.style.TextAlign.Center)    }}